import React from 'react';
import { FontAwesomeIcon } from '@fortawesome/react-fontawesome';
import { faEnvelope } from '@fortawesome/free-solid-svg-icons';
import './HeaderContent.css';

const HeaderContent = () => {
    const currentUrlAddress = window.location.href;
    return (
        <div className="main-header-container">
            <div className="header-logo">
                <a href={currentUrlAddress}><img />Logo image</a>
            </div>
            <div className="header-contact-email">
                <a href="mailto:zonezoneyang@gmail.com"><FontAwesomeIcon className="font-awsome-header-contact-email" icon={faEnvelope} size="3x" color="#ffa500" /></a>
            </div>
        </div>
    )
}

export default HeaderContent;
